const ingresosRows = $('Query ER Ingresos').all().map(i => i.json);
const gastosRows = $('Query ER Gastos').all().map(i => i.json);
const totalIngresos = ingresosRows.reduce((s, r) => s + Number(r.total || 0), 0);
const totalGastos = gastosRows.reduce((s, r) => s + Number(r.total || 0), 0);
const neto = totalIngresos - totalGastos;
const margen = totalIngresos ? neto / totalIngresos : 0;
return [{ json: {
  ingresos: { total: totalIngresos, lineas: ingresosRows },
  gastos: { total: totalGastos, lineas: gastosRows },
  resultado: { neto, margen }
} }];
